        // PaymentFee service
        let payment_fee_repository = Arc::new(PaymentFeeRepository::new(db_pool.clone()));
        let payment_fee_service = Arc::new(PaymentFeeService::with_repository(payment_fee_repository.clone()));

        // Invoice service
        let invoice_repository = Arc::new(InvoiceRepository::new(db_pool.clone()));
        let invoice_service = Arc::new(InvoiceService::with_repository(invoice_repository.clone()));

        // InvoiceParty service
        let invoice_party_repository = Arc::new(InvoicePartyRepository::new(db_pool.clone()));
        let invoice_party_service = Arc::new(InvoicePartyService::with_repository(invoice_party_repository.clone()));

        // InvoiceLineItem service
